import React, { useState } from 'react';
import { Link, useLocation, Outlet } from 'react-router-dom';

const AdminLayout = () => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const location = useLocation();

  const navigation = [
    {
      name: 'Dashboard',
      href: '/admin',
      icon: '📊',
      current: location.pathname === '/admin'
    },
    {
      name: 'User Management',
      href: '/admin/users',
      icon: '👥',
      current: location.pathname === '/admin/users'
    },
    {
      name: 'Restaurant Management',
      href: '/admin/restaurants',
      icon: '🏪',
      current: location.pathname === '/admin/restaurants'
    },
    {
      name: 'Order Monitoring',
      href: '/admin/orders',
      icon: '📦',
      current: location.pathname === '/admin/orders'
    },
    {
      name: 'Delivery Partners',
      href: '/admin/delivery-partners',
      icon: '🚴',
      current: location.pathname === '/admin/delivery-partners'
    },
    {
      name: 'Analytics & Reports',
      href: '/admin/analytics',
      icon: '📈',
      current: location.pathname === '/admin/analytics'
    },
    {
      name: 'Promotions',
      href: '/admin/promotions',
      icon: '🎯',
      current: location.pathname === '/admin/promotions'
    },
    {
      name: 'Payment Management',
      href: '/admin/payments',
      icon: '💳',
      current: location.pathname === '/admin/payments'
    },
    {
      name: 'Content Management',
      href: '/admin/content',
      icon: '📝',
    },
    {
      name: 'System Security',
      href: '/admin/security',
      icon: '🔒',
      current: location.pathname === '/admin/security'
    }
  ];

  const quickStats = [
    { label: 'Active Orders', value: '24', color: 'text-orange-600' },
    { label: 'Pending Approvals', value: '3', color: 'text-red-600' },
    { label: 'System Status', value: 'Good', color: 'text-green-600' }
  ];

  return (
    <div className="min-h-screen bg-gray-50 flex">
      {/* Sidebar */}
      <div className={`${sidebarOpen ? 'w-64' : 'w-16'} bg-white shadow-lg transition-all duration-300 flex flex-col`}>
        {/* Logo */}
        <div className="flex items-center justify-between p-4 border-b">
          {sidebarOpen && (
            <div className="flex items-center space-x-2">
              <div className="w-8 h-8 bg-orange-500 rounded-lg flex items-center justify-center">
                <span className="text-white font-bold">F</span>
              </div>
              <div>
                <h1 className="text-lg font-bold text-gray-900">FoodieExpress</h1>
                <p className="text-xs text-gray-600">Admin Panel</p>
              </div>
            </div>
          )}
          <button
            onClick={() => setSidebarOpen(!sidebarOpen)}
            className="p-2 rounded-lg hover:bg-gray-100 transition-colors"
          >
            <span className="text-gray-600">{sidebarOpen ? '◀' : '▶'}</span>
          </button>
        </div>

        {/* Quick Stats */}
        {sidebarOpen && (
          <div className="p-4 border-b">
            <h3 className="text-sm font-medium text-gray-700 mb-3">Quick Stats</h3>
            <div className="space-y-2">
              {quickStats.map((stat, index) => (
                <div key={index} className="flex items-center justify-between text-sm">
                  <span className="text-gray-600">{stat.label}</span>
                  <span className={`font-semibold ${stat.color}`}>{stat.value}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Navigation */}
        <nav className="flex-1 p-4 space-y-2">
          {navigation.map((item) => (
            <Link
              key={item.name}
              to={item.href}
              className={`flex items-center space-x-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                item.current
                  ? 'bg-orange-100 text-orange-700'
                  : 'text-gray-700 hover:bg-gray-100'
              }`}
            >
              <span className="text-lg">{item.icon}</span>
              {sidebarOpen && <span>{item.name}</span>}
            </Link>
          ))}
        </nav>

        {/* Admin Profile */}
        <div className="p-4 border-t">
          <div className="flex items-center space-x-3">
            <div className="w-8 h-8 bg-gray-300 rounded-full flex items-center justify-center">
              <span className="text-gray-600 text-sm">👤</span>
            </div>
            {sidebarOpen && (
              <div>
                <p className="text-sm font-medium text-gray-900">Admin User</p>
                <p className="text-xs text-gray-600">admin@foodieexpress.com</p>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Top Header */}
        <div className="bg-white shadow-sm border-b px-6 py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-4">
              <h2 className="text-xl font-semibold text-gray-900">
                {navigation.find(item => item.current)?.name || 'Admin Panel'}
              </h2>
            </div>

            <div className="flex items-center space-x-4">
              {/* Notifications */}
              <button className="relative p-2 text-gray-600 hover:text-gray-900 transition-colors">
                <span className="text-xl">🔔</span>
                <span className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 text-white text-xs rounded-full flex items-center justify-center">
                  3
                </span>
              </button>

              {/* Quick Actions */}
              <div className="flex items-center space-x-2">
                <button className="bg-orange-500 text-white px-3 py-1 rounded text-sm hover:bg-orange-600 transition-colors">
                  + New Order
                </button>
                <button className="bg-green-500 text-white px-3 py-1 rounded text-sm hover:bg-green-600 transition-colors">
                  📊 Reports
                </button>
              </div>

              {/* Settings */}
              <button className="p-2 text-gray-600 hover:text-gray-900 transition-colors">
                <span className="text-xl">⚙️</span>
              </button>

              {/* Logout */}
              <Link
                to="/"
                className="bg-red-500 text-white px-3 py-1 rounded text-sm hover:bg-red-600 transition-colors"
              >
                Logout
              </Link>
            </div>
          </div>
        </div>

        {/* Page Content */}
        <div className="flex-1 overflow-auto">
          <Outlet />
        </div>

        {/* Footer */}
        <div className="bg-white border-t px-6 py-3">
          <div className="flex items-center justify-between text-sm text-gray-600">
            <div>
              © 2024 FoodieExpress Admin Panel. All rights reserved.
            </div>
            <div className="flex items-center space-x-4">
              <span>Version 1.0.0</span>
              <span>•</span>
              <span>Last updated: {new Date().toLocaleDateString()}</span>
              <span>•</span>
              <span className="flex items-center space-x-1">
                <span className="w-2 h-2 bg-green-500 rounded-full"></span>
                <span>System Online</span>
              </span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AdminLayout;
